class Solution:
    def maximumGroups(self, grades):
        n = len(grades)
        g = 0
        used = 0
        while used + (g + 1) <= n:
            g += 1
            used += g
        return g

solutions.python:
class Solution:
    def maximumGroups(self, grades):
        n = len(grades)
        # largest g with g*(g+1)/2 <= n
        lo, hi = 0, 200000
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if mid * (mid + 1) // 2 <= n:
                lo = mid
            else:
                hi = mid - 1
        return lo

