var maximumGroups = function(grades) {
    const n = grades.length;
    let lo = 0, hi = 200000;
    while (lo < hi) {
        const mid = Math.floor((lo + hi + 1) / 2);
        if (mid * (mid + 1) / 2 <= n) lo = mid;
        else hi = mid - 1;
    }
    return lo;
};
